function processData(input) {
  try {
    // Parse agent response
    let contentAnalysis;
    if (typeof input.content === 'string') {
      // Try to parse as JSON string
      try {
        contentAnalysis = JSON.parse(input.content);
      } catch (e) {
        // If JSON parsing fails, use as text
        contentAnalysis = {
          mainTopic: input.content,
          targetAudience: 'General',
          contentType: 'blog',
          keywords: []
        };
      }
    } else {
      contentAnalysis = input.content;
    }

    // Determine content type
    const contentType = contentAnalysis.contentType || 'blog';

    // Normalize content type
    let normalizedType = contentType.toLowerCase();
    if (normalizedType.includes('blog') || normalizedType.includes('article')) {
      normalizedType = 'blog';
    } else if (normalizedType.includes('social') || normalizedType.includes('post')) {
      normalizedType = 'social';
    } else if (normalizedType.includes('email') || normalizedType.includes('newsletter')) {
      normalizedType = 'email';
    }

    return {
      contentType: normalizedType,
      analysis: contentAnalysis,
      metadata: {
        processingTime: new Date().toISOString(),
        confidence: getConfidenceScore(contentAnalysis)
      }
    };
  } catch (error) {
    return {
      contentType: 'blog',
      analysis: {
        mainTopic: input.content || 'Unspecified',
        targetAudience: 'General',
        contentType: 'blog',
        keywords: []
      },
      error: error.message
    };
  }
}

// Helper function to calculate confidence score
function getConfidenceScore(analysis) {
  let score = 0;
  if (analysis.mainTopic && analysis.mainTopic.length > 5) score += 0.3;
  if (analysis.targetAudience && analysis.targetAudience.length > 3) score += 0.2;
  if (analysis.contentType) score += 0.2;
  if (analysis.keywords && analysis.keywords.length > 0) score += 0.3;
  return Math.min(score, 1.0);
}

function processData(input) {
  // Simply return the input as the final output
  return input;
}
